// generate more vocab items to reach 950
function gv(id, word, hindi, sm, ipa, syn, ant, daily, office, inter, biz, note, cefr) {
  const base = word; const s3 = word+"s"; const ing = word+"ing"; const past = word+"ed"; const pp = word+"ed";
  return {id, word, hindi, simpleMeaning:sm, ipa, verbForms:{base, s3, ing, past, pastParticiple:pp}, synonyms:syn, antonyms:ant, sentences:{daily, office, interview:inter, business:biz, formal:`The organization shall ${word} this appropriately.`, informal:`Just ${word} it — trust me.`}, usageNote:note, cefrLevel:cefr};
}

