// build vocab from fillVocabList
const baseVocabLen = allVocab.length;
fillVocabList.forEach((row, i) => {
  const id = baseVocabLen + i + 1;
  const [word, hindi, sm, ipa, syn, ant, daily, office, inter, biz, note, cefr] = row;
  const base = word; const s3 = word+"s"; const ing = word.endsWith("e") ? word+"ing" : word+"ing"; const past = word+"d"; const pp = word+"d";
  allVocab.push({id, word, hindi, simpleMeaning:sm, ipa, verbForms:{base, s3, ing, past, pastParticiple:pp}, synonyms:syn, antonyms:ant, sentences:{daily, office, interview:inter, business:biz, formal:`The organization shall ${word} this according to regulations.`, informal:`Just ${word} it.`}, usageNote:note, cefrLevel:cefr});
});

allVocab = allVocab.slice(0, 950);
allVocab.forEach((w, i) => { w.id = i+1; });

const vocabOut = {
  day: 3,
  title: "Imperative Sentences — 950 Vocabulary Words",
  totalWords: allVocab.length,
  words: allVocab
};
fs.writeFileSync("data/challenge/day-03/vocabulary.json", JSON.stringify(vocabOut, null, 2));
console.log("Vocab written:", allVocab.length);

