function tr(id, hindi, correct, distractors, exp) {
  return {id, type:"translate", hindi, options:[...distractors.map(d=>({english:d, hindi:d})), correct], answer:correct, explanation:`Correct translation: "${hindi}" = "${correct}"`};
}
function fill(id, sentence, answer, options, exp) {
  return {id, type:"fill", sentence, options, answer, explanation:exp||`The missing word is "${answer}".`};
}
function err(id, wrong, correct, exp) {
  return {id, type:"error", sentence:wrong, options:[wrong, correct], answer:correct, explanation:exp||`Correct sentence: "${correct}".`};
}
function mcq(id, question, options, answer, exp) {
  return {id, type:"mcq", question, options, answer, explanation:exp};
}

